Patching the snake game now.
_____javascript
return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "/source",
      value: `export default function SnakeGame() {
  const GRID_SIZE = 20
  const CELL_SIZE = 20
  const TICK_MS = 140
  const MOVE_MS = 120

  const [direction, setDirection] = React.useState({ x: 1, y: 0 })
  const [nextDirection, setNextDirection] = React.useState({ x: 1, y: 0 })
  const [snake, setSnake] = React.useState([
    { x: 10, y: 10 },
    { x: 9, y: 10 },
    { x: 8, y: 10 }
  ])
  const [snakePrev, setSnakePrev] = React.useState([
    { x: 10, y: 10 },
    { x: 9, y: 10 },
    { x: 8, y: 10 }
  ])
  const [snakeAnimating, setSnakeAnimating] = React.useState([
    { x: 10, y: 10 },
    { x: 9, y: 10 },
    { x: 8, y: 10 }
  ])
  const [food, setFood] = React.useState({ x: 14, y: 10 })
  const [score, setScore] = React.useState(0)
  const [running, setRunning] = React.useState(true)

  const moveSnake = React.useCallback(() => {
    setSnake(prev => {
      const head = { x: prev[0].x + direction.x, y: prev[0].y + direction.y }
      if (head.x < 0 || head.y < 0 || head.x >= GRID_SIZE || head.y >= GRID_SIZE) {
        setRunning(false)
        return prev
      }

      const ate = head.x === food.x && head.y === food.y
      const next = [head, ...prev]
      if (!ate) next.pop()

      setSnakePrev(prev)
      setSnakeAnimating(prev)
      if (ate) {
        setScore(s => s + 1)
        setFood({
          x: Math.floor(Math.random() * GRID_SIZE),
          y: Math.floor(Math.random() * GRID_SIZE)
        })
      }
      return next
    })
  }, [direction, food])

  React.useEffect(() => {
    const timer = setInterval(moveSnake, TICK_MS)
    return () => clearInterval(timer)
  }, [moveSnake])

  React.useEffect(() => {
    const anim = setInterval(() => {
      setSnakeAnimating(curr => {
        return curr.map((segment, i) => {
          const prev = snakePrev[i] || snakePrev[snakePrev.length - 1]
          const next = snake[i] || snake[snake.length - 1] || prev
          return {
            x: prev.x + (next.x - prev.x) * 0.85,
            y: prev.y + (next.y - prev.y) * 0.85
          }
        })
      })
    }, MOVE_MS / 6)
    return () => clearInterval(anim)
  }, [snake, snakePrev])

  React.useEffect(() => {
    const onKeyDown = e => {
      const dirs = {
        ArrowUp: { x: 0, y: -1 },
        ArrowDown: { x: 0, y: 1 },
        ArrowLeft: { x: -1, y: 0 },
        ArrowRight: { x: 1, y: 0 }
      }
      const nd = dirs[e.key]
      if (!nd) return
      if (nd.x === -direction.x && nd.y === -direction.y) return
      setNextDirection(nd)
    }
    window.addEventListener("keydown", onKeyDown)
    return () => window.removeEventListener("keydown", onKeyDown)
  }, [direction])

  React.useEffect(() => {
    setDirection(nextDirection)
  }, [nextDirection])

  return (
    <div
      style={{
        display: "grid",
        placeItems: "center",
        height: "100%",
        background: "#111"
      }}
    >
      <div style={{ color: "#fff", marginBottom: 12 }}>Score: {score}</div>
      <div
        style={{
          width: GRID_SIZE * CELL_SIZE,
          height: GRID_SIZE * CELL_SIZE,
          position: "relative",
          background: "#1a1a1a",
          border: "2px solid #333",
          overflow: "hidden"
        }}
      >
        {snakeAnimating.map((segment, idx) => (
          <div
            key={idx}
            style={{
              position: "absolute",
              left: segment.x * CELL_SIZE + 1,
              top: segment.y * CELL_SIZE + 1,
              width: CELL_SIZE - 2,
              height: CELL_SIZE - 2,
              borderRadius: idx === 0 ? 8 : 6,
              background: idx === 0 ? "#7CFF6B" : "#34c759",
              boxShadow: "0 0 10px rgba(124,255,107,0.18)",
              transition: `left ${MOVE_MS}ms linear, top ${MOVE_MS}ms linear, transform ${MOVE_MS}ms ease-out`
            }}
          />
        ))}
        <div
          style={{
            position: "absolute",
            left: food.x * CELL_SIZE + 3,
            top: food.y * CELL_SIZE + 3,
            width: CELL_SIZE - 6,
            height: CELL_SIZE - 6,
            borderRadius: "50%",
            background: "#ff4d4d",
            boxShadow: "0 0 12px rgba(255,77,77,0.4)"
          }}
        />
      </div>
    </div>
  )
}`
    }
  ]
})

