(async () => {
  function pickArea() {
    const doc = document;
    const el = doc.scrollingElement || doc.documentElement || doc.body;
    const width = Math.max(el.scrollWidth, doc.documentElement.clientWidth, window.innerWidth);
    const height = Math.max(el.scrollHeight, doc.documentElement.clientHeight, window.innerHeight);
    return { width, height };
  }

  const { width, height } = pickArea();
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext("2d");

  ctx.fillStyle = "#ffffff";
  ctx.fillRect(0, 0, width, height);

  const svg = `
    <svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}">
      <foreignObject width="100%" height="100%">
        <div xmlns="http://www.w3.org/1999/xhtml" style="font-family: Arial, sans-serif; color: #000; background: #fff; width: ${width}px; height: ${height}px;">
          <div style="padding: 24px;">
            <div style="font-size: 20px; font-weight: 700; margin-bottom: 12px;">Screenshot unavailable</div>
            <div style="font-size: 14px;">This runtime does not provide a direct DOM-to-image screenshot API.</div>
          </div>
        </div>
      </foreignObject>
    </svg>`;

  const img = new Image();
  const blob = new Blob([svg], { type: "image/svg+xml;charset=utf-8" });
  const url = URL.createObjectURL(blob);

  await new Promise((resolve, reject) => {
    img.onload = () => {
      ctx.drawImage(img, 0, 0);
      URL.revokeObjectURL(url);
      resolve();
    };
    img.onerror = reject;
    img.src = url;
  });

  const dataUrl = canvas.toDataURL("image/png");
  const a = document.createElement("a");
  a.href = dataUrl;
  a.download = "screenshot.png";
  a.click();

  return "Downloaded screenshot.png";
})()

