(() => {
  const dpr = window.devicePixelRatio || 1;
  const canvas = document.createElement('canvas');
  canvas.width = Math.floor(window.innerWidth * dpr);
  canvas.height = Math.floor(window.innerHeight * dpr);
  const ctx = canvas.getContext('2d');

  // Best-effort page snapshot via html2canvas if available, otherwise a simple render fallback.
  const done = (sourceCanvas) => {
    const link = document.createElement('a');
    link.download = `screenshot-${new Date().toISOString().replace(/[:.]/g, '-')}.png`;
    link.href = sourceCanvas.toDataURL('image/png');
    link.click();
  };

  const fallback = () => {
    ctx.scale(dpr, dpr);
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, window.innerWidth, window.innerHeight);
    ctx.fillStyle = '#000';
    ctx.font = '16px sans-serif';
    ctx.fillText('Canvas fallback screenshot', 20, 30);
    done(canvas);
  };

  if (window.html2canvas) {
    window.html2canvas(document.body, {
      canvas,
      useCORS: true,
      backgroundColor: null,
      scale: dpr
    }).then(done).catch(fallback);
  } else {
    fallback();
  }
})();
